class Solution:
    def pathSum(self, root: Optional[TreeNode], targetSum: int) -> int:
        cnt = defaultdict(int); cnt[0] = 1
        def dfs(node, s):
            if not node: return 0
            s += node.val
            ans = cnt[s - targetSum]
            cnt[s] += 1
            ans += dfs(node.left, s) + dfs(node.right, s)
            cnt[s] -= 1
            return ans
        return dfs(root, 0)

