class Solution {
public:
    int pathSum(TreeNode* root, int t) {
        unordered_map<long long,int> cnt; cnt[0]=1;
        function<int(TreeNode*,long long)> dfs=[&](TreeNode* n,long long s)->int{
            if(!n) return 0;
            s+=n->val; int ans=cnt[s-t];
            cnt[s]++; ans+=dfs(n->left,s)+dfs(n->right,s); cnt[s]--;
            return ans;
        };
        return dfs(root,0);
    }
};
